import React from "React"
import ContentLayout from "./ContentLayout"
import { css } from "@emotion/core"
import { Link, graphql, useStaticQuery } from "gatsby"
import { breakpoints } from "../utils/theme"
import Img from "gatsby-image"
import TypeformButton from "./TypeformButton"
import DownloadButton from "./DownloadButton.js"

import { colors } from "../utils/theme"

export default props => {
  const data = useStaticQuery(graphql`
    query {
      file(relativePath: { eq: "heroScreenshot.png" }) {
        childImageSharp {
          fluid {
            ...GatsbyImageSharpFluid
          }
        }
      }
    }
  `)

  return (
    <div>
      <div
        css={css`
          clip-path: polygon(0 0, 100% 0%, 100% 90%, 0 100%);
          @media (max-width: ${breakpoints.md}) {
            clip-path: polygon(0 0, 100% 0%, 100% 95%, 0 100%);
          }
        `}
      >
        <ContentLayout bg={props.bg}>
          <div
            css={css`
              display: flex;
              align-items: center;
              margin: -2rem;
              margin-top: 2rem;
              margin-bottom: 2rem;
              @media (max-width: ${breakpoints.md}) {
                flex-direction: column;
                margin-top: 1rem;
                margin-bottom: 1rem;
              }
            `}
          >
            <div
              css={css`
                width: 50%;
                padding: 2rem;
                @media (max-width: ${breakpoints.md}) {
                  width: 100%;
                }
              `}
            >
              <h1
                css={css`
                  font-weight: normal;
                  color: ${colors.primary.darker};
                `}
              >
                Easiest way to keep your team in the loop about your company
                news.
              </h1>
              <h2
                css={css`
                  font-weight: normal;
                  color: ${colors.primary.darker};
                `}
              >
                Your company home from a new tab, the lightest way to centralize
                and share company updates.
              </h2>

              <DownloadButton text="Get started" />
            </div>
            <div
              css={css`
                width: 50%;
                height: 100%;
                padding: 2rem;
                @media (max-width: ${breakpoints.md}) {
                  width: 100%;
                  margin: 0px 100px 100px 100px;
                }
              `}
            >
              <Img
                css={css`
                  border-radius: 5px;
                  box-shadow: 0 0 50px 0 rgba(0, 0, 0, 0.25);
                `}
                fluid={data.file.childImageSharp.fluid}
                alt="zenshare app extension"
              />
            </div>
          </div>
        </ContentLayout>
      </div>
    </div>
  )
}
